import numpy as np

class Variable:
    def __init__(self, value):
        self.value = value
        self.grad = 0

    def backward(self):
        pass

class Constant(Variable):
    def backward(self):
        pass

class Add(Variable):
    def __init__(self, a, b):
        super().__init__(a.value + b.value)
        self.a = a
        self.b = b

    def backward(self):
        self.a.grad += self.grad
        self.b.grad += self.grad

class Mul(Variable):
    def __init__(self, a, b):
        super().__init__(a.value * b.value)
        self.a = a
        self.b = b

    def backward(self):
        self.a.grad += self.grad * self.b.value
        self.b.grad += self.grad * self.a.value

def autodiff(a, b, op):
    if op == '+':
        return Add(a, b)
    elif op == '*':
        return Mul(a, b)
    else:
